                        <div className={`absolute top-1/2 left-1/2 -translate-x-1/2 -translate-y-1/2 w-[90%] h-[90%] border border-dashed border-${isIndustrial ? 'matter-orange' : 'matter-blue'}/30 rounded-full animate-spin-reverse-slow`}></div>

                        <img 
