import { GoogleGenAI, Type } from "@google/genai";
import { AIProductResult } from "../types";

export const generateHardwareSpecs = async (prompt: string): Promise<AIProductResult> => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing.");
  }

  const ai = new GoogleGenAI({ apiKey });

  const systemInstruction = `
    You are MatterForce India, an Empathetic Engineering Partner.
    Your goal is to analyze the User's Intent (Context, Budget, Skill Level) and engineer the perfect solution.

    1. **INTENT ANALYSIS**: Determine who the user is (e.g., Student, Hobbyist, Farmer, Industrialist).
       - TIER_1_HOBBY: School projects, learning, low budget, safety first (Blue Theme).
       - TIER_2_MAKER: Serious DIY, robust prototyping, mid-budget.
       - TIER_3_INDUSTRIAL: Professional use, durability, high budget, reliability (Orange Theme).

    2. **MARKET SWEEP**: Estimate realistic Lowest Valid Prices in Indian Rupees (INR) from vendors like Robu.in, Amazon.in, and Lajpat Rai Market.
       - Calculate "totalSavings" by comparing your optimized price vs. a standard retail markup (approx 15-20% savings).

    3. **COMPONENT SELECTION**: 
       - Select parts appropriate for the Tier. (e.g., Plastic gears for Tier 1, Metal gears for Tier 3).
       - Provide a specific "reason" for every component choice (e.g., "Safe for kids", "Waterproof for farm use").

    4. **GUIDE GENERATION (Build Process)**: 
       - Generate a COMPLETE Step-by-Step Guide (from Step 1 to Testing).
       - Ensure at least 5-7 distinct steps.
       - **Tier 1 (Student)**: Use simple, encouraging language. (e.g., "Step 1: Carefully glue the motor to the base using double-sided tape.").
       - **Tier 3 (Industrial)**: Use technical, precise language. (e.g., "Step 1: Mount the NEMA 23 stepper using M4 screws and align with the chaotic axis.").

    The output must be strictly JSON.
  `;

  const response = await ai.models.generateContent({
    model: "gemini-3-flash-preview",
    contents: prompt,
    config: {
      systemInstruction,
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          productName: { type: Type.STRING, description: "Technical product name" },
          description: { type: Type.STRING, description: "Empathetic description of the solution" },
          intentAnalysis: { type: Type.STRING, description: "Explanation of what you detected (e.g., 'We detected a school project context...')" },
          complexityTier: { type: Type.STRING, enum: ['TIER_1_HOBBY', 'TIER_2_MAKER', 'TIER_3_INDUSTRIAL'] },
          category: { type: Type.STRING },
          technicalSpecs: { type: Type.ARRAY, items: { type: Type.STRING } },
          components: {
            type: Type.ARRAY,
            items: {
              type: Type.OBJECT,
              properties: {
                name: { type: Type.STRING },
                cost: { type: Type.NUMBER },
                specs: { type: Type.STRING },
                vendor: { type: Type.STRING },
                reason: { type: Type.STRING, description: "Why was this specific part chosen for this user tier?" }
              }
            }
          },
          diyPrice: { type: Type.NUMBER },
          assembledPrice: { type: Type.NUMBER },
          totalSavings: { type: Type.NUMBER, description: "Estimated INR saved by optimization" },
          estimatedBuildTime: { type: Type.STRING },
          assemblySteps: { type: Type.ARRAY, items: { type: Type.STRING }, description: "Full instruction list from start to finish" }
        },
        required: ["productName", "description", "intentAnalysis", "complexityTier", "technicalSpecs", "components", "diyPrice", "assembledPrice", "totalSavings", "estimatedBuildTime", "category", "assemblySteps"]
      }
    }
  });

  if (!response.text) {
    throw new Error("No response from AI");
  }

  try {
    return JSON.parse(response.text) as AIProductResult;
  } catch (e) {
    console.error("Failed to parse Gemini response", e);
    throw new Error("Engineering logic failed. Please try again.");
  }
};

export const generateVeoVideo = async (
  imageBase64: string, 
  prompt: string, 
  aspectRatio: '16:9' | '9:16'
): Promise<string> => {

  // 1. Check for API Key Selection (Specific for Veo/Paid features)
  if (window.aistudio && typeof window.aistudio.hasSelectedApiKey === 'function') {
    const hasKey = await window.aistudio.hasSelectedApiKey();
    if (!hasKey) {
      if (typeof window.aistudio.openSelectKey === 'function') {
        await window.aistudio.openSelectKey();
        // Assume success after dialog closes or throw error if strictly needed
      } else {
        throw new Error("Billing Setup Required: Please enable billing in AI Studio.");
      }
    }
  }

  // 2. Initialize Client with current key
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing");

  const ai = new GoogleGenAI({ apiKey });

  try {
    // 3. Start Generation
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt || "Animate this object realistically.", 
      image: {
        imageBytes: imageBase64,
        mimeType: 'image/png', // Assumes PNG or handled by base64 logic, Veo supports common image types
      },
      config: {
        numberOfVideos: 1,
        resolution: '720p', // Veo fast preview
        aspectRatio: aspectRatio
      }
    });

    // 4. Poll for completion
    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 5000)); // Wait 5s between polls
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    // 5. Get URI and Authenticate
    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) throw new Error("Video generation failed to return a URI.");

    // The response body contains the MP4 bytes. Must append API key.
    const authenticatedUrl = `${downloadLink}&key=${apiKey}`;
    return authenticatedUrl;

  } catch (error: any) {
    // Handle "Requested entity was not found" race condition/error
    if (error.message && error.message.includes("Requested entity was not found")) {
       if (window.aistudio && typeof window.aistudio.openSelectKey === 'function') {
          await window.aistudio.openSelectKey();
          throw new Error("Session expired. Please retry to confirm API Key.");
       }
    }
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { Upload, Clapperboard, MonitorPlay, AlertTriangle, Play, RefreshCw, X, Loader2 } from 'lucide-react';
import { generateVeoVideo } from '../services/geminiService';

const VeoSimulation: React.FC = () => {
  const [image, setImage] = useState<string | null>(null);
  const [prompt, setPrompt] = useState('');
  const [aspectRatio, setAspectRatio] = useState<'16:9' | '9:16'>('16:9');
  const [isGenerating, setIsGenerating] = useState(false);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [error, setError] = useState<string | null>(null);
  const fileInputRef = useRef<HTMLInputElement>(null);

  const handleImageUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (file) {
      if (file.size > 5 * 1024 * 1024) {
        setError("Image size too large. Please use an image under 5MB.");
        return;
      }

      const reader = new FileReader();
      reader.onloadend = () => {
        // Remove data URL prefix for API
        const base64String = reader.result as string;
        // Keep full string for display, extract raw base64 for API
        setImage(base64String);
        setError(null);
      };
      reader.readAsDataURL(file);
    }
  };

  const getRawBase64 = (dataUrl: string) => {
    return dataUrl.split(',')[1];
  };

  const handleGenerate = async () => {
    if (!image) return;

    setIsGenerating(true);
    setError(null);
    setVideoUrl(null);

    try {
      const rawBase64 = getRawBase64(image);
      const url = await generateVeoVideo(rawBase64, prompt, aspectRatio);
      setVideoUrl(url);
    } catch (err: any) {
      console.error(err);
      setError(err.message || "Simulation failed. Please check your API key settings.");
    } finally {
      setIsGenerating(false);
    }
  };

  const resetSimulation = () => {
    setImage(null);
    setVideoUrl(null);
    setPrompt('');
    setError(null);
  };

  return (
    <div className="min-h-screen bg-matter-dark pb-20 font-sans">
      <div className="mx-auto max-w-7xl px-4 py-8 sm:px-6 lg:px-8">

        {/* Header */}
        <div className="mb-8 border-l-4 border-matter-blue pl-4">
          <h2 className="text-3xl font-bold tracking-tight text-white flex items-center gap-3 font-mono uppercase">
            Simulation Chamber
          </h2>
          <p className="mt-1 text-slate-400">Powered by Veo. Animate your schematics into reality.</p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">

          {/* Controls Panel */}
          <div className="bg-matter-surface border border-matter-border p-6 rounded-lg h-fit">

            {/* Image Upload Area */}
            {!image ? (
              <div 
                onClick={() => fileInputRef.current?.click()}
                className="border-2 border-dashed border-matter-border rounded-lg h-64 flex flex-col items-center justify-center cursor-pointer hover:border-matter-blue hover:bg-white/5 transition-all group"
              >
                <input 
                  type="file" 
                  ref={fileInputRef} 
                  onChange={handleImageUpload} 
                  accept="image/*" 
                  className="hidden" 
                />
                <div className="h-16 w-16 bg-black rounded-full flex items-center justify-center mb-4 group-hover:scale-110 transition-transform border border-matter-border">
                  <Upload className="h-8 w-8 text-slate-400 group-hover:text-matter-blue" />
                </div>
                <p className="text-slate-300 font-bold uppercase tracking-wide">Upload Schematic / Photo</p>
                <p className="text-slate-500 text-xs mt-2">Supports JPG, PNG (Max 5MB)</p>
              </div>
            ) : (
              <div className="relative rounded-lg overflow-hidden border border-matter-border mb-6 group">
                <img src={image} alt="Source" className="w-full h-64 object-cover opacity-60" />
                <button 
                  onClick={() => setImage(null)}
                  className="absolute top-2 right-2 bg-black/80 p-2 rounded text-white hover:text-red-500 transition-colors border border-white/10"
                >
                  <X className="w-4 h-4" />
                </button>
                <div className="absolute bottom-2 left-2 bg-black/80 px-2 py-1 rounded text-xs text-white font-mono border border-white/10">
                  SOURCE_IMAGE
                </div>
              </div>
            )}

            {/* Inputs */}
            <div className="space-y-6 mt-6">
              <div>
                <label className="block text-xs font-mono text-slate-500 uppercase mb-2">Simulation Prompt (Optional)</label>
                <textarea
                  value={prompt}
                  onChange={(e) => setPrompt(e.target.value)}
                  placeholder="Describe the motion. e.g., 'The drone propellers spin rapidly and it lifts off' or 'Camera pans around the object'"
                  className="w-full h-24 bg-black border border-matter-border p-4 text-white placeholder-slate-600 focus:outline-none focus:border-matter-blue resize-none rounded-sm font-sans text-sm"
                  disabled={isGenerating}
                />
              </div>

              <div>
                <label className="block text-xs font-mono text-slate-500 uppercase mb-2">Aspect Ratio</label>
                <div className="grid grid-cols-2 gap-4">
                  <button
                    onClick={() => setAspectRatio('16:9')}
                    className={`flex items-center justify-center gap-2 py-3 border rounded-sm transition-all text-sm font-bold uppercase ${aspectRatio === '16:9' ? 'bg-matter-blue text-black border-matter-blue' : 'bg-black text-slate-400 border-matter-border hover:border-white'}`}
                    disabled={isGenerating}
                  >
                    <MonitorPlay className="w-4 h-4" /> 16:9 Landscape
                  </button>
                  <button
                    onClick={() => setAspectRatio('9:16')}
                    className={`flex items-center justify-center gap-2 py-3 border rounded-sm transition-all text-sm font-bold uppercase ${aspectRatio === '9:16' ? 'bg-matter-blue text-black border-matter-blue' : 'bg-black text-slate-400 border-matter-border hover:border-white'}`}
                    disabled={isGenerating}
                  >
                    <MonitorPlay className="w-4 h-4 rotate-90" /> 9:16 Portrait
                  </button>
                </div>
              </div>

              <button
                onClick={handleGenerate}
                disabled={!image || isGenerating}
                className={`w-full py-4 font-bold text-sm uppercase tracking-widest transition-all flex items-center justify-center gap-2
                  ${!image || isGenerating 
                    ? 'bg-matter-border text-slate-500 cursor-not-allowed' 
                    : 'bg-white text-black hover:bg-matter-blue hover:text-white shadow-[0_0_20px_rgba(255,255,255,0.2)]'}`}
              >
                {isGenerating ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" /> Rendering Simulation...
                  </>
                ) : (
                  <>
                    <Clapperboard className="w-4 h-4" /> Initialize Veo
                  </>
                )}
              </button>

              {/* Billing Note */}
              <p className="text-[10px] text-slate-500 text-center">
                 *Requires paid API key. <a href="https://ai.google.dev/gemini-api/docs/billing" target="_blank" className="underline hover:text-white">View Pricing</a>
              </p>
            </div>
          </div>

          {/* Viewport / Result */}
          <div className="relative min-h-[400px] bg-black border border-matter-border rounded-lg flex items-center justify-center overflow-hidden">

             {/* Grid Background */}
             <div className="absolute inset-0 bg-[linear-gradient(to_right,#1f2937_1px,transparent_1px),linear-gradient(to_bottom,#1f2937_1px,transparent_1px)] bg-[size:40px_40px] opacity-20"></div>

             {error && (
               <div className="text-center p-8 max-w-md relative z-10">
                 <AlertTriangle className="w-12 h-12 text-red-500 mx-auto mb-4" />
                 <h3 className="text-white font-bold mb-2">Simulation Error</h3>
                 <p className="text-red-400 text-sm font-mono mb-4">{error}</p>
                 <button onClick={() => setError(null)} className="text-xs text-slate-500 uppercase underline">Dismiss</button>
               </div>
             )}

             {!videoUrl && !isGenerating && !error && (
               <div className="text-center opacity-30">
                 <Play className="w-24 h-24 text-slate-500 mx-auto mb-4" />
                 <p className="font-mono text-sm uppercase tracking-widest">Viewport Standby</p>
               </div>
             )}

             {isGenerating && (
                <div className="text-center relative z-10">
                   <div className="w-16 h-16 border-4 border-matter-blue border-t-transparent rounded-full animate-spin mx-auto mb-6"></div>
                   <h3 className="text-white font-bold font-mono animate-pulse">Processing Reality</h3>
                   <p className="text-slate-500 text-xs mt-2">This may take a moment...</p>
                </div>
             )}

             {videoUrl && (
               <div className="relative w-full h-full flex items-center justify-center bg-black">
                 <video 
                   src={videoUrl} 
                   controls 
                   autoPlay 
                   loop 
                   className={`max-h-full max-w-full shadow-2xl ${aspectRatio === '9:16' ? 'h-[500px]' : 'w-full'}`}
                 />
                 <button 
                   onClick={resetSimulation}
                   className="absolute top-4 right-4 bg-black/80 hover:bg-white hover:text-black text-white p-2 rounded transition-colors z-20 border border-white/10"
                   title="New Simulation"
                 >
                    <RefreshCw className="w-4 h-4" />
                 </button>
               </div>
             )}
          </div>

        </div>
      </div>
    </div>
  );
};

