                    <div className="flex flex-wrap gap-1 mb-4">
                      {product.specs.slice(0, 2).map((spec, idx) => (
                        <span key={idx} className="text-[10px] bg-slate-900 text-slate-400 px-1.5 py-0.5 border border-matter-border">
                          {spec}
